const raw = items[0].json;

const symbols = typeof raw.symbols === "string"
  ? raw.symbols.split(",").map(s => s.trim())
  : raw.symbols || ["^FCHI", "BNP.PA", "AIR.PA", "MC.PA", "OR.PA", "ORA.PA"];

return symbols.map(symbol => ({
  json: {
    symbol,
    interval: raw.interval || "1d",
    period: raw.period || "1y",
  }
}));

// Données originales venant de "Prepare Payload"
const orig = $item(0).$node["Prepare Payload"].json || {};
// Réponse de ton backend (node HTTP Request)
const resp = $json || {};

const candles = Array.isArray(resp.candles) ? resp.candles : [];

// ---- Fonctions utilitaires ----
function extractCloses(candles) {
  const closes = [];
  for (const c of candles) {
    let v = c.c;
    if (typeof v === "string") {
      v = parseFloat(v.replace(",", "."));
    }
    if (Number.isFinite(v)) {
      closes.push(v);
    }
  }
  return closes;
}

function computeStats(candles) {
  const closes = extractCloses(candles);
  const n = closes.length;

  if (n === 0) {
    return {
      first_close: null,
      last_close: null,
      pct_change: null,
      volatility: null,
      trend: "Inconnue",
      signal: "NEUTRE",
    };
  }

  const first = closes[0];
  const last = closes[n - 1];
  const pct_change = first !== 0 ? ((last - first) / first) * 100 : 0;

  // Rendements journaliers
  const rets = [];
  for (let i = 1; i < n; i++) {
    const prev = closes[i - 1];
    const cur = closes[i];
    if (prev && prev !== 0) {
      rets.push(cur / prev - 1);
    }
  }

  let vol = null;
  if (rets.length > 1) {
    const mean =
      rets.reduce((acc, r) => acc + r, 0) / rets.length;
    let varSum = 0;
    for (const r of rets) {
      varSum += (r - mean) * (r - mean);
    }
    const variance = varSum / (rets.length - 1);
    // Vol annualisée (approx) * 100 pour %
    vol = Math.sqrt(variance) * Math.sqrt(252) * 100;
  }

  let trend = "Latérale";
  let signal = "NEUTRE";

  if (pct_change > 8) {
    trend = "Haussière";
    signal = "ACHAT";
  } else if (pct_change < -8) {
    trend = "Baissière";
    signal = "VENTE";
  }

  return {
    first_close: first,
    last_close: last,
    pct_change,
    volatility: vol,
    trend,
    signal,
  };
}

const stats = computeStats(candles);

return {
  json: {
    // symbole robuste
    symbol: resp.symbol || orig.symbol || "UNKNOWN",

    nb_candles: candles.length,

    source: resp.source || "yfinance",
    interval: resp.interval || orig.interval || null,
    period: resp.period || orig.period || null,

    // 🔥 Nouveaux champs enrichis
    first_close: stats.first_close,
    last_close: stats.last_close,
    pct_change: stats.pct_change,
    volatility: stats.volatility,
    trend: stats.trend,
    signal: stats.signal,

    error_message: resp.error?.message || null,
    error_status: resp.error?.status || null,

    fetched_at: new Date().toISOString(),
  },
};
